  1	import { PrometheusEndpoint, PrometheusResponse } from '@openshift-console/dynamic-plugin-sdk';
  2	import {
  3	  EmptyState,
  4	  EmptyStateBody,
  5	  EmptyStateVariant,
  6	  PerPageOptions,
  7	} from '@patternfly/react-core';
  8	import {
  9	  ISortBy,
 10	  Table as PFTable,
 11	  sortable,
 12	  TableGridBreakpoint,
 13	  TableVariant,
 14	  Tbody,
 15	  Td,
 16	  Th,
 17	  Thead,
 18	  Tr,
 19	} from '@patternfly/react-table';
 20	import * as _ from 'lodash-es';
 21	import * as React from 'react';
 22	import { useTranslation } from 'react-i18next';
 23	
 24	import ErrorAlert from '../shared/error';
 25	import { getPrometheusURL } from '../../console/graphs/helpers';
 26	import { usePoll } from '../../console/utils/poll-hook';
 27	import { useSafeFetch } from '../../console/utils/safe-fetch-hook';
 28	
 29	import { formatNumber } from '../../format';
 30	import { usePerspective } from '../../hooks/usePerspective';
 31	import TablePagination from '../../table-pagination';
 32	import { ColumnStyle, Panel } from './types';
 33	import { CustomDataSource } from '@openshift-console/dynamic-plugin-sdk/lib/extensions/dashboard-data-source';
 34	
 35	type AugmentedColumnStyle = ColumnStyle & {
 36	  className?: string;
 37	};
 38	
 39	// Get the columns from the panel styles. Filters out hidden columns and orders
 40	// them so the label columns are displayed first.
 41	const getColumns = (styles: ColumnStyle[]): AugmentedColumnStyle[] => {
 42	  const labelColumns = [];
 43	  const valueColumns = [];
 44	  styles.forEach((col: ColumnStyle) => {
 45	    // Remove hidden or regex columns.
 46	    if (col.type === 'hidden' || col.pattern.startsWith('/') || !col.alias) {
 47	      return;
 48	    }
 49	
 50	    if (col.pattern.startsWith('Value #')) {
 51	      valueColumns.push(col);
 52	    } else if (col.pattern === 'Value') {
 53	      // Set the column to use the first group pattern because the panel has a single target
 54	      valueColumns.push({ ...col, pattern: 'Value #A' });
 55	    } else {
 56	      labelColumns.push({
 57	        ...col,
 58	        className: 'monitoring-dashboards__label-column-header',
 59	      });
 60	    }
 61	  });
 62	
 63	  // Show non-value columns first.
 64	  return [...labelColumns, ...valueColumns];
 65	};
 66	
 67	const perPageOptions: PerPageOptions[] = [5, 10, 20, 50, 100].map((n) => ({
 68	  title: n.toString(),
 69	  value: n,
 70	}));
 71	
 72	const Table: React.FC<Props> = ({ customDataSource, panel, pollInterval, queries, namespace }) => {
 73	  const { t } = useTranslation(process.env.I18N_NAMESPACE);
 74	  const { perspective } = usePerspective();
 75	
 76	  const [error, setError] = React.useState();
 77	  const [isLoading, setLoading] = React.useState(true);
 78	  const [data, setData] = React.useState();
 79	  const [page, setPage] = React.useState(1);
 80	  const [perPage, setPerPage] = React.useState(5);
 81	  const [sortBy, setSortBy] = React.useState<ISortBy>({ index: 0, direction: 'asc' });
 82	  const onSort = (e, index: ISortBy['index'], direction: ISortBy['direction']) =>
 83	    setSortBy({ index, direction });
 84	  // eslint-disable-next-line react-hooks/exhaustive-deps
 85	  const safeFetch = React.useCallback(useSafeFetch(), []);
 86	
 87	  const tick = () => {
 88	    const allPromises = _.map(queries, (query) =>
 89	      _.isEmpty(query)
 90	        ? Promise.resolve()
 91	        : safeFetch(
 92	            getPrometheusURL(
 93	              {
 94	                endpoint: PrometheusEndpoint.QUERY,
 95	                query,
 96	                namespace: perspective === 'dev' ? namespace : '',
 97	              },
 98	              perspective,
 99	              customDataSource?.basePath,
100	            ),
101	          ),
102	    );
103	
104	    Promise.all(allPromises)
105	      .then((responses: PrometheusResponse[]) => {
106	        setError(undefined);
107	        setLoading(false);
108	        // Note: This makes the following assumptions about the data:
109	        // 1. The transform is `table`
110	        // 2. The value will be an instance vector (single value).
111	        // 3. The time column is hidden.
112	        // The Grafana implementation is much more involved. See
113	        //   https://grafana.com/docs/grafana/latest/features/panels/table_panel/#merge-multiple-queries-per-table
114	        setData(
115	          responses.reduce((acc, response, i: number) => {
116	            if (response) {
117	              const id = panel.targets[i].refId;
118	              response.data.result.forEach(({ metric, value }) => {
119	                const tag = Object.values(metric).join('-');
120	                if (!acc[tag]) {
121	                  acc[tag] = { ...metric };
122	                }
123	                acc[tag][`Value #${id}`] = value[1] || '';
124	              });
125	            }
126	            return acc;
127	          }, {} as any),
128	        );
129	      })
130	      .catch((err) => {
131	        if (err.name !== 'AbortError') {
132	          setError(_.get(err, 'json.error', err.message));
133	          setLoading(false);
134	          setData(undefined);
135	        }
136	      });
137	  };
138	
139	  usePoll(tick, pollInterval, queries);
140	  if (isLoading) {
141	    return <div className="loading-skeleton--table" />;
142	  }
143	  if (error) {
144	    return <ErrorAlert error={{ message: error, name: t('An error occurred') }} />;
145	  }
146	  if (_.isEmpty(panel.styles)) {
147	    return (
148	      <ErrorAlert
149	        error={{ message: t('panel.styles attribute not found'), name: t('An error occurred') }}
150	      />
151	    );
152	  }
153	  if (_.isEmpty(data)) {
154	    return (
155	      <EmptyState variant={EmptyStateVariant.xs}>
156	        <EmptyStateBody>{t('No data found')}</EmptyStateBody>
157	      </EmptyState>
158	    );
159	  }
160	
161	  const columns: AugmentedColumnStyle[] = getColumns(panel.styles);
162	
163	  // Sort the data.
164	  const sort = (row) => {
165	    const { pattern, type } = columns[sortBy.index];
166	    const val = row[pattern];
167	    if (type !== 'number') {
168	      return val;
169	    }
170	    if (_.isNil(val)) {
171	      return Number.MIN_VALUE;
172	    }
173	    const num = Number(val);
174	    // Some columns styles claim to be numbers, but have string data. Still sort those as strings.
175	    return _.isFinite(num) ? num : val;
176	  };
177	  const sortedData = _.orderBy(data, [sort], [sortBy.direction]);
178	  const visibleData = sortedData.slice((page - 1) * perPage, page * perPage);
179	
180	  // Format the table rows.
181	  const rows: string[][] = visibleData.map((values: { [key: string]: string }) => {
182	    return columns.reduce((acc: string[], { type, decimals = 2, pattern, unit = '' }) => {
183	      const value = values[pattern];
184	      switch (type) {
185	        case 'number':
186	          acc.push(formatNumber(value, decimals, unit));
187	          break;
188	        default:
189	          acc.push(value || '-');
190	      }
191	      return acc;
192	    }, []);
193	  });
194	
195	  const headers = columns.map(({ alias: title, className }) => ({
196	    title,
197	    transforms: [sortable],
198	    ...(className ? { props: { className } } : {}),
199	  }));
200	
201	  return (
202	    <>
203	      <div className="monitoring-dashboards__table-container">
204	        <PFTable
205	          aria-label={t('query results table')}
206	          className="monitoring-dashboards__table"
207	          gridBreakPoint={TableGridBreakpoint.none}
208	          variant={TableVariant.compact}
209	          rows={rows.length}
210	        >
211	          <Thead>
212	            <Tr>
213	              {headers.map(({ title }, columnIndex) => {
214	                const sortParams = {
215	                  sort: {
216	                    sortBy,
217	                    onSort,
218	                    columnIndex,
219	                  },
220	                };
221	                return (
222	                  <Th key={`title-${columnIndex}`} {...sortParams}>
223	                    {title}
224	                  </Th>
225	                );
226	              })}
227	            </Tr>
228	          </Thead>
229	          <Tbody>
230	            {rows.map((_, rowIndex) => (
231	              <Tr key={`row-${rowIndex}`}>
232	                {headers.map((_, columnIndex) => (
233	                  <Td
234	                    key={`cell-${rowIndex}-${columnIndex}`}
235	                    dataLabel={rows?.[rowIndex]?.[columnIndex] ?? ''}
236	                  >
237	                    {rows?.[rowIndex]?.[columnIndex]}
238	                  </Td>
239	                ))}
240	              </Tr>
241	            ))}
242	          </Tbody>
243	        </PFTable>
244	      </div>
245	      <TablePagination
246	        itemCount={sortedData.length}
247	        page={page}
248	        perPage={perPage}
249	        perPageOptions={perPageOptions}
250	        setPage={setPage}
251	        setPerPage={setPerPage}
252	      />
253	    </>
254	  );
255	};
256	
257	type Props = {
258	  panel: Panel;
259	  pollInterval: number;
260	  queries: string[];
261	  namespace?: string;
262	  customDataSource?: CustomDataSource;
263	};
264	
265	export default Table;

